 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { modelToRef } from '@kubevirt-ui/kubevirt-api/console';
 5	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Label, LabelGroup } from '@patternfly/react-core';
 7	
 8	import './MetadataLabels.scss';
 9	
10	type MetadataLabelsProps = {
11	  labels?: { [key: string]: string };
12	  model: K8sModel;
13	};
14	
15	const MetadataLabels: FC<MetadataLabelsProps> = ({ labels, model }) => {
16	  const modelRef = modelToRef(model);
17	
18	  return (
19	    <LabelGroup className="metadata-labels-group" numLabels={10}>
20	      {Object.keys(labels || {})?.map((key) => {
21	        const labelText = labels[key] ? `${key}=${labels[key]}` : key;
22	
23	        return (
24	          <Label className="co-label" key={key}>
25	            <Link
26	              className="pf-v6-c-label__content"
27	              to={`/search?kind=${modelRef}&q=${encodeURIComponent(labelText)}`}
28	            >
29	              {labelText}
30	            </Link>
31	          </Label>
32	        );
33	      })}
34	    </LabelGroup>
35	  );
36	};
37	
38	export default MetadataLabels;

